import React, { useId } from 'react';
import { Card, CardContent, Box, Typography, Stack } from '@mui/material';
import { ResponsiveChartContainer, BarPlot, ChartsXAxis, ChartsYAxis, ChartsClipPath } from '@mui/x-charts';
import response from './response.json';

interface ErrorRateTrend {
  hour: string;
  rate: number;
}

interface ApiUsageData {
  requestCount: number;
  averageLatencyMs: number;
  errorRate: number;
  errorRateTrend: ErrorRateTrend[];
}

export default function Widget() {
  const apiUsageData = response.data as ApiUsageData;
  const clipPathId = useId();

  return (
    <Card sx={{ width: 'fit-content', minWidth: 350, maxWidth: 450, bgcolor: '#121212' }} elevation={2}>
      <CardContent sx={{ p: 2.5 }}>
        <Stack spacing={2}>
          <Box>
            <Typography variant="body2" color="text.secondary">
              API Usage
            </Typography>
            <Typography variant="h4" fontWeight={700} sx={{ color: '#BB86FC' }}>
              {apiUsageData.requestCount.toLocaleString()} Requests
            </Typography>
            <Typography variant="body2" color="text.secondary">
              Avg Latency: {apiUsageData.averageLatencyMs} ms
            </Typography>
            <Typography variant="body2" color="text.secondary">
              Error Rate: {apiUsageData.errorRate}%
            </Typography>
          </Box>

          <Box sx={{ width: '100%', height: 200 }}>
            <ResponsiveChartContainer
              series={[
                {
                  type: 'bar',
                  data: apiUsageData.errorRateTrend.map((t) => t.rate),
                  color: '#FF5722',
                  label: 'Error Rate',
                },
              ]}
              xAxis={[
                {
                  scaleType: 'band',
                  data: apiUsageData.errorRateTrend.map((t) => t.hour),
                  id: 'hours',
                },
              ]}
              yAxis={[{ id: 'errorRate' }]}
            >
              <g clipPath={`url(#${clipPathId})`}>
                <BarPlot />
              </g>
              <ChartsXAxis
                axisId="hours"
                tickLabelStyle={{ fontSize: 10, fill: '#E0E0E0' }}
              />
              <ChartsYAxis
                axisId="errorRate"
                tickLabelStyle={{ fontSize: 10, fill: '#E0E0E0' }}
              />
              <ChartsClipPath id={clipPathId} />
            </ResponsiveChartContainer>
          </Box>
        </Stack>
      </CardContent>
    </Card>
  );
}
